def json_body(schema_ref_or_obj, description="بدنهٔ درخواست"):
    schema = schema_ref_or_obj if isinstance(schema_ref_or_obj, dict) and "$ref" in schema_ref_or_obj else schema_ref_or_obj
    return {
        "description": description,
        "required": True,
        "content": {"application/json": {"schema": schema}},
    }


def multipart_body(schema_ref_or_obj, description="بدنهٔ درخواست (multipart برای پیوست فایل)"):
    return {
        "description": description,
        "required": True,
        "content": {"multipart/form-data": {"schema": schema_ref_or_obj}},
    }


def resp(status, description, schema=None):
    r = {"description": description}
    if schema is not None:
        r["content"] = {"application/json": {"schema": schema}}
    return {str(status): r}


def ref_resp(name):
    return {"$ref": f"#/components/responses/{name}"}


def query_param(name, required=False, ptype="string", enum=None, default=None, description=""):
    schema = {"type": ptype}
    if enum:
        schema["enum"] = enum
    if default is not None:
        schema["default"] = default
    return {
        "name": name,
        "in": "query",
        "required": required,
        "description": description,
        "schema": schema,
    }


def path_param(name, ptype="integer", description=""):
    return {
        "name": name,
        "in": "path",
        "required": True,
        "description": description,
        "schema": {"type": ptype},
    }


