BEARER_SECURITY = [{"bearerAuth": []}]


def op(summary, tags, roles, operation_id, params=None, request_body=None, responses=None, description=""):
    o = {
        "summary": summary,
        "operationId": operation_id,
        "tags": tags,
        "security": BEARER_SECURITY if roles != ["Public"] else [],
        "x-roles": roles,
        "description": description or summary,
    }
    if params:
        o["parameters"] = params
    if request_body:
        o["requestBody"] = request_body
    o["responses"] = responses or {}
    return o


